DROP DATABASE IF EXISTS MoviesDB;
CREATE DATABASE MoviesDB;
USE MoviesDB;

CREATE TABLE Users (
    UserID        VARCHAR(20)  PRIMARY KEY,
    FirstName     VARCHAR(50),
    LastName      VARCHAR(50),
    Email         VARCHAR(100),
    UserType      VARCHAR(20),
    FavoriteGenre VARCHAR(50),
    Password      VARCHAR(255)
);

CREATE TABLE Movies (
    MovieID           VARCHAR(20)  PRIMARY KEY,
    ReleaseYear       INT,
    Title             VARCHAR(255),
    PosterURL         VARCHAR(255),
    PrimaryStreamingService VARCHAR(255),
    Genre             VARCHAR(100),
    Rating            DECIMAL(3,1),
    Description       VARCHAR(255)
);

CREATE TABLE Reviews (
    ReviewID VARCHAR(20) PRIMARY KEY,
    MovieID  VARCHAR(20),
    UserID   VARCHAR(20),
    Score    INT,
    Text     TEXT,
    FOREIGN KEY (MovieID) REFERENCES Movies(MovieID),
    FOREIGN KEY (UserID)  REFERENCES Users(UserID)
);

CREATE TABLE Actors (
    ActorID               VARCHAR(20) PRIMARY KEY,
    MovieID               VARCHAR(20),
    Actor_Name            VARCHAR(255) NOT NULL,
    FOREIGN KEY (MovieID) REFERENCES Movies(MovieID)
    );









SELECT u.UserID, COUNT(r.ReviewID) AS ReviewCount
FROM Users u
LEFT JOIN Reviews r ON u.UserID = r.UserID
GROUP BY u.UserID;
