INSERT INTO Movies (MovieID, ReleaseYear, Title, PosterURL, PrimaryStreamingService, Genre, Rating, Description) VALUES
('tt0012349', 1921, 'The Kid',                                        'Poster URL', 'The Criterion Channel', 'Comedy',    8.3, 'A pompous millionaire finds his carefree existence turned upside down when a resourceful young orphan enters his life and refuses to leave.'),
('tt0027977', 1936, 'Modern Times',                                   'Poster URL', 'The Criterion Channel', 'Romance',   8.5, 'A factory worker struggles to survive the pressures of industrial life while falling for a homeless young woman, together searching for a better future.'),
('tt0034583', 1942, 'Casablanca',                                     'Poster URL', 'Amazon Prime Video',    'Drama',     8.5, 'In wartime Morocco, a cynical American nightclub owner must choose between love and virtue when his former lover arrives with her fugitive husband seeking transit papers.'),
('tt0038650', 1946, 'It''s a Wonderful Life',                         'Poster URL', 'Amazon Prime Video',    'Family',    8.6, 'A despairing small-town man is granted the chance to see what life would have been like for his community had he never been born, guided by his bumbling guardian angel.'),
('tt0047396', 1954, 'Rear Window',                                    'Poster URL', 'Amazon Prime Video',    'Thriller',  8.5, 'A photographer confined to a wheelchair becomes convinced he has witnessed a murder through his apartment window, drawing his girlfriend into a dangerous investigation.'),
('tt0051201', 1957, 'Witness for the Prosecution',                    'Poster URL', 'Amazon Prime Video',    'Crime',     8.4, 'A brilliant but ailing barrister takes on the seemingly unwinnable case of a man accused of murder, only to be blindsided by shocking courtroom revelations.'),
('tt0054215', 1960, 'Psycho',                                         'Poster URL', 'Peacock',               'Horror',    8.5, 'A secretary on the run with stolen money checks into a remote motel run by a peculiar young man dominated by his mysterious mother, with terrifying consequences.'),
('tt0057012', 1964, 'Dr. Strangelove',                                'Poster URL', 'Amazon Prime Video',    'War',       8.4, 'A deranged general triggers a nuclear crisis that sets off a chain of absurd events, leaving the President and his advisors scrambling to avert World War III.'),
('tt0060196', 1966, 'The Good, the Bad and the Ugly',                 'Poster URL', 'Pluto TV',              'Adventure', 8.8, 'Three gunslingers compete in a dangerous race across the American Southwest to find a buried cache of Confederate gold during the Civil War.'),
('tt0068646', 1972, 'The Godfather',                                  'Poster URL', 'Paramount+',            'Crime',     9.2, 'The aging patriarch of an organized crime dynasty transfers control of his empire to his reluctant son, sparking a bloody war among the New York Mafia families.'),
('tt0071562', 1974, 'The Godfather Part II',                          'Poster URL', 'Paramount+',            'Crime',     9.0, 'The rise of a young Vito Corleone in early 20th-century New York unfolds in parallel with his son Michael''s ruthless consolidation of the family''s criminal empire.'),
('tt0073195', 1975, 'Jaws',                                           'Poster URL', 'Peacock',               'Thriller',  8.1, 'A small beach town is terrorized by a massive great white shark, forcing the local police chief, a marine biologist, and a grizzled shark hunter to join forces.'),
('tt0073486', 1975, 'One Flew Over the Cuckoo''s Nest',               'Poster URL', 'Amazon Prime Video',    'Drama',     8.7, 'A free-spirited man fakes insanity to serve his prison sentence in a mental institution, where he clashes with the iron-fisted Nurse Ratched and inspires his fellow patients.'),
('tt0080684', 1980, 'Star Wars: Episode V - The Empire Strikes Back', 'Poster URL', 'Disney+',               'Action',    8.7, 'After the Rebel Alliance suffers a devastating defeat, Luke Skywalker trains with the legendary Yoda while his friends are hunted across the galaxy by Darth Vader.'),
('tt0081505', 1980, 'The Shining',                                    'Poster URL', 'Max',                   'Horror',    8.4, 'A writer becomes the winter caretaker of an isolated mountain hotel, where supernatural forces and cabin fever drive him to terrifying madness, threatening his family.'),
('tt0086250', 1983, 'Scarface',                                       'Poster URL', 'Amazon Prime Video',    'Crime',     8.3, 'A Cuban refugee arrives in Miami with nothing and claws his way to the top of the cocaine trade, only to see his empire crumble under the weight of his paranoia and excess.'),
('tt0088763', 1985, 'Back to the Future',                             'Poster URL', 'Amazon Prime Video',    'Sci-Fi',    8.5, 'A teenager is accidentally sent back to 1955 in a time-traveling DeLorean and must ensure his parents fall in love while finding a way back to the future.'),
('tt0090605', 1986, 'Aliens',                                         'Poster URL', 'Amazon Prime Video',    'Sci-Fi',    8.4, 'Ripley returns to the moon where her crew first encountered the deadly xenomorphs, this time accompanied by a unit of marines who are in for the fight of their lives.'),
('tt0093779', 1987, 'The Princess Bride',                             'Poster URL', 'Disney+',               'Adventure', 8.0, 'A bedridden boy listens to his grandfather read a fairy tale about a farmhand-turned-pirate who races to rescue his one true love from a villainous prince.'),
('tt0095016', 1988, 'Die Hard',                                       'Poster URL', 'Amazon Prime Video',    'Action',    8.2, 'A New York cop visiting his estranged wife in Los Angeles becomes the only hope for hostages when a group of terrorists seize a Nakatomi Plaza skyscraper on Christmas Eve.'),
('tt0095067', 2002, 'Eight Crazy Nights',                             'Poster URL', 'Hulu',                  'Comedy',    6.7, 'An animated Hanukkah musical comedy following a party-hard slacker who is sentenced to community service as a youth basketball referee under a kindhearted but eccentric volunteer.'),
('tt0095327', 1988, 'Grave of the Fireflies',                         'Poster URL', 'Netflix',               'Animation', 8.5, 'In the final months of World War II, a teenage boy struggles to care for his younger sister after they are orphaned by American firebombing raids in Japan.'),
('tt0095765', 1988, 'Cinema Paradiso',                                'Poster URL', 'Amazon Prime Video',    'Drama',     8.5, 'A celebrated film director reflects on his childhood in postwar Sicily, where a projectionist at the local cinema became a father figure who shaped his lifelong love of movies.'),
('tt0095953', 1988, 'Rain Man',                                       'Poster URL', 'Pluto TV',              'Drama',     8.0, 'A self-centered car dealer discovers he has a brother — an autistic savant — and kidnaps him from an institution in hopes of claiming his inheritance, leading to an unexpected cross-country bond.'),
('tt0097165', 1989, 'Dead Poets Society',                             'Poster URL', 'Disney+',               'Drama',     8.1, 'An unconventional English teacher at a prestigious prep school inspires his students to seize the day through poetry and free thought, with life-altering consequences.'),
('tt0097576', 1989, 'Indiana Jones and the Last Crusade',             'Poster URL', 'Amazon Prime Video',    'Action',    8.2, 'Archaeologist Indiana Jones teams up with his estranged father to race against the Nazis in a globe-trotting search for the legendary Holy Grail.'),
('tt0099685', 1990, 'Goodfellas',                                     'Poster URL', 'Max',                   'Biography', 8.7, 'The true story of Henry Hill, who grows up in a mob family and works his way up through the criminal underworld, until drugs, paranoia, and betrayal lead to his downfall.'),
('tt0101414', 1991, 'Beauty and the Beast',                           'Poster URL', 'Disney+',               'Fantasy',   8.0, 'A bright young woman is taken prisoner by a fearsome enchanted Beast in his magical castle and begins to see beyond his monstrous exterior to the man hidden within.'),
('tt0102926', 1991, 'The Silence of the Lambs',                       'Poster URL', 'Hulu',                  'Thriller',  8.6, 'An FBI trainee seeks the help of the brilliant but terrifyingly manipulative cannibalistic psychiatrist Hannibal Lecter to catch a serial killer who skins his victims.'),
('tt0103064', 1991, 'Terminator 2: Judgment Day',                     'Poster URL', 'Amazon Prime Video',    'Sci-Fi',    8.6, 'A reprogrammed Terminator is sent back in time to protect teenage John Connor from a more advanced and lethal shape-shifting machine bent on his destruction.'),
('tt0105236', 1992, 'Reservoir Dogs',                                 'Poster URL', 'Amazon Prime Video',    'Thriller',  8.3, 'After a diamond heist goes violently wrong, the surviving criminals hole up in a warehouse and try to figure out which one of them is the police informant.'),
('tt0105695', 1992, 'Unforgiven',                                     'Poster URL', 'Max',                   'Western',   8.2, 'A retired outlaw takes on one last job alongside his old partner and a young gunfighter to collect a bounty on two cowboys who mutilated a prostitute.'),
('tt0107048', 1993, 'Groundhog Day',                                  'Poster URL', 'Netflix',               'Drama',     8.0, 'A cynical TV weatherman finds himself inexplicably reliving the same small-town Groundhog Day over and over, forced to examine his life and find meaning in the loop.'),
('tt0107290', 1993, 'Jurassic Park',                                  'Poster URL', 'Peacock',               'Sci-Fi',    8.2, 'A billionaire''s dream of cloning dinosaurs for a theme park turns into a nightmare when the prehistoric predators break free and begin hunting the stranded visitors.'),
('tt0108052', 1993, 'Schindler''s List',                              'Poster URL', 'Peacock',               'History',   9.0, 'Based on the true story of Oskar Schindler, a German industrialist who saved the lives of more than a thousand Jewish refugees during the Holocaust by employing them in his factories.'),
('tt0109830', 1994, 'Forrest Gump',                                   'Poster URL', 'Paramount+',            'Romance',   8.8, 'A kind-hearted man from Alabama with a low IQ inadvertently witnesses and influences many defining moments in 20th-century American history while searching for his childhood love.'),
('tt0110357', 1994, 'The Lion King',                                  'Poster URL', 'Disney+',               'Animation', 8.5, 'A young lion prince flees his kingdom after the murder of his father and must find the courage to return, claim his throne, and face his treacherous uncle.'),
('tt0110912', 1994, 'Pulp Fiction',                                   'Poster URL', 'Paramount+',            'Crime',     8.9, 'The lives of two mob hitmen, a boxer, a gangster, and a pair of diner bandits intertwine in four tales of violence and redemption in Los Angeles.'),
('tt0111161', 1994, 'The Shawshank Redemption',                       'Poster URL', 'Max',                   'Drama',     9.3, 'An innocent banker is sentenced to life in Shawshank Prison and forms an unlikely friendship with a seasoned inmate, finding hope and redemption through sheer perseverance.'),
('tt0118799', 1997, 'Life Is Beautiful',                              'Poster URL', 'Pluto TV',              'Romance',   8.6, 'A charming Jewish Italian man uses his imagination and humor to shield his young son from the horrors of a Nazi concentration camp by convincing him it is all an elaborate game.'),
('tt0120601', 1999, 'Being John Malkovich',                           'Poster URL', 'Amazon Prime Video',    'Comedy',    7.7, 'A struggling puppeteer discovers a mysterious portal that leads directly into the mind of movie star John Malkovich, sparking an identity-bending obsession.'),
('tt0120737', 2001, 'The Lord of the Rings: The Fellowship of the Ring', 'Poster URL', 'Max',               'Adventure', 8.8, 'A young hobbit embarks on an epic quest to destroy a powerful and corrupting ring, accompanied by a fellowship of heroes against the growing darkness of an ancient evil.'),
('tt0120815', 1998, 'Saving Private Ryan',                            'Poster URL', 'Paramount+',            'War',       8.6, 'Following the Normandy invasion, a captain leads a squad of soldiers deep behind enemy lines on a dangerous mission to find and bring home a paratrooper whose brothers have all been killed in action.'),
('tt0133093', 1999, 'The Matrix',                                     'Poster URL', 'Max',                   'Action',    8.7, 'A computer hacker learns the world he lives in is a simulated reality created by machines, and joins a rebellion of freed humans fighting to overthrow their captors.'),
('tt0137523', 1999, 'Fight Club',                                     'Poster URL', 'Amazon Prime Video',    'Drama',     8.8, 'An insomniac office worker forms an underground fight club with a charismatic soap salesman, which evolves into something far more dangerous and anarchic than either man imagined.'),
('tt0167260', 2003, 'The Lord of the Rings: The Return of the King',  'Poster URL', 'Amazon Prime Video',   'Adventure', 8.9, 'Aragorn leads the forces of Middle-earth against the armies of Sauron in a final battle to distract the Dark Lord while Frodo and Sam make their last desperate push to destroy the One Ring.'),
('tt0209144', 2000, 'Memento',                                        'Poster URL', 'Amazon Prime Video',    'Mystery',   8.4, 'A man suffering from anterograde amnesia uses tattoos and Polaroid photos to track down the man he believes murdered his wife, piecing together a mystery the audience experiences in reverse.'),
('tt0317248', 2002, 'City of God',                                    'Poster URL', 'Amazon Prime Video',    'Crime',     8.6, 'A young photographer chronicles the brutal rise of organized crime in Rio de Janeiro''s most dangerous favela during the 1960s and 70s, striving to escape the violence around him.'),
('tt0364569', 2003, 'Oldboy',                                         'Poster URL', 'Netflix',               'Action',    8.4, 'A man imprisoned in a cell for 15 years without explanation is suddenly released and given five days to find out who imprisoned him — and why — uncovering a devastating truth.'),
('tt0407887', 2006, 'The Departed',                                   'Poster URL', 'Netflix',               'Thriller',  8.5, 'In Boston, an undercover cop infiltrates the Irish mob while a mole within the police force reports back to the gang leaders, each racing to expose the other before being discovered.'),
('tt0468569', 2008, 'The Dark Knight',                                'Poster URL', 'Max',                   'Action',    9.0, 'Batman faces his greatest threat when a criminal mastermind known as the Joker rises from the Gotham underworld and plunges the city into anarchy, testing the hero''s moral limits.'),
('tt0816692', 2014, 'Interstellar',                                   'Poster URL', 'Paramount+',            'Sci-Fi',    8.7, 'A former NASA pilot leads a crew of astronauts through a wormhole near Saturn in search of a new habitable planet as Earth faces environmental collapse, leaving his family behind.'),
('tt1375666', 2010, 'Inception',                                      'Poster URL', 'Amazon Prime Video',    'Action',    8.8, 'A skilled thief who specializes in stealing secrets from people''s dreams is offered a chance to have his criminal record erased if he can successfully plant an idea in a target''s subconscious.'),
('tt1675434', 2011, 'The Intouchables',                               'Poster URL', 'Netflix',               'Biography', 8.5, 'A wealthy French aristocrat paralyzed from the neck down forms an unlikely and life-changing friendship with an irreverent young man from the projects hired to be his caretaker.'),
('tt2119532', 2016, 'Hacksaw Ridge',                                  'Poster URL', 'Amazon Prime Video',    'War',       8.1, 'The true story of Desmond Doss, a conscientious objector who refused to carry a weapon but served as a combat medic in World War II and single-handedly saved 75 men at the Battle of Okinawa.'),
('tt2380307', 2017, 'Coco',                                           'Poster URL', 'Disney+',               'Family',    8.4, 'A young aspiring musician is transported to the Land of the Dead on Dia de Muertos, where he embarks on an extraordinary journey to find his great-great-grandfather and uncover his family''s history.'),
('tt2582802', 2014, 'Whiplash',                                       'Poster URL', 'Netflix',               'Drama',     8.5, 'An ambitious young jazz drummer at a prestigious music conservatory is pushed to his mental and physical limits by a ruthless, manipulative conductor obsessed with perfection.'),
('tt8267604', 2019, 'Parasite',                                       'Poster URL', 'Hulu',                  'Comedy',    8.5, 'A poor Korean family schemes to become employed by a wealthy household, but their plan takes a dark and shocking turn when an unexpected secret is discovered beneath the mansion.'),
('tt8267676', 2024, 'Poppy Playtime',                                 'Poster URL', 'Amazon Prime Video',    'Horror',    1.0, 'One man explores an abandoned Playtime Co. toy factory to uncover the mystery of his missing coworkers.'),
('tt8673952', 2025, 'A Minecraft Movie',                              'Poster URL', 'Max',                   'Comedy',    5.6, 'Four misfits are transported through a portal into the blocky Overworld. They team up with expert crafter Steve to fight back against Malgosha and her army of invading piglins.'),
('tt9046728', 2024, 'Cheese: The Movie',                              'Poster URL', 'Tubi',                  'Comedy',    0.1, 'One fox named Colby travels the world in search of his true purpose.');
INSERT INTO Reviews (ReviewID, MovieID, UserID, Score, Text) VALUES
('rev_001', 'tt0111161', 'user_035', 10, 'A perfect film in every way. The storytelling, acting, and emotional depth are unmatched.'),
('rev_002', 'tt0468569', 'user_012',  9, 'Heath Ledger''s performance is legendary. The tension throughout keeps you on edge.'),
('rev_003', 'tt1375666', 'user_028',  8, 'Mind-bending concept executed brilliantly. Takes multiple viewings to fully appreciate.'),
('rev_004', 'tt0099685', 'user_005',  9, 'Scorsese at his finest. The energy and dialogue are electric from start to finish.'),
('rev_005', 'tt0109830', 'user_041',  7, 'A heartwarming journey through American history. Hanks delivers another great performance.'),
('rev_006', 'tt0068646', 'user_019', 10, 'The greatest American film ever made. Every scene is iconic and perfectly crafted.'),
('rev_007', 'tt0137523', 'user_023',  9, 'The twist still catches me off guard even after multiple watches. So thought-provoking.'),
('rev_008', 'tt0120737', 'user_002',  9, 'A breathtaking start to the trilogy. The world-building is extraordinary.'),
('rev_009', 'tt0081505', 'user_016',  8, 'Kubrick''s direction creates an unsettling atmosphere that stays with you.'),
('rev_010', 'tt0108052', 'user_008', 10, 'Devastating and essential viewing. A powerful reminder of humanity''s darkest chapter.'),
('rev_011', 'tt0110912', 'user_031',  9, 'Tarantino''s dialogue is unmatched. The nonlinear structure keeps it fresh every time.'),
('rev_012', 'tt0167260', 'user_044', 10, 'An epic conclusion to an epic saga. The battle sequences are cinema at its best.'),
('rev_013', 'tt0071562', 'user_016',  9, 'A rare sequel that matches the original. Michael''s descent into darkness is compelling.'),
('rev_014', 'tt0133093', 'user_027',  8, 'Revolutionary for its time. The bullet time scenes changed action films forever.'),
('rev_015', 'tt0102926', 'user_023',  9, 'Hopkins is terrifying as Lecter. A masterclass in building suspense.'),
('rev_016', 'tt0054215', 'user_003',  8, 'Hitchcock''s masterpiece. The shower scene still holds up after all these years.'),
('rev_017', 'tt0097576', 'user_045',  7, 'A fun adventure with great chemistry between Ford and Connery.'),
('rev_018', 'tt0088763', 'user_022',  9, 'Pure joy from beginning to end. The DeLorean is one of cinema''s great icons.'),
('rev_019', 'tt0110357', 'user_048',  8, 'Beautiful animation and unforgettable songs. It still makes me emotional.'),
('rev_020', 'tt0120815', 'user_009',  9, 'The opening D-Day sequence is gut-wrenching. A powerful tribute to the Greatest Generation.'),
('rev_021', 'tt0080684', 'user_014',  9, 'The best Star Wars film. The revelation about Vader is perfectly set up.'),
('rev_022', 'tt0103064', 'user_033',  8, 'Incredible effects for its time. The T-1000 is a terrifying villain.'),
('rev_023', 'tt0364569', 'user_026',  9, 'Brutal and unforgettable. The corridor fight scene is one of the best ever.'),
('rev_024', 'tt0038650', 'user_007',  8, 'A heartwarming classic that reminds us what''s truly important in life.'),
('rev_025', 'tt0057012', 'user_043',  8, 'The darkest comedy ever made. Peter Sellers is brilliant in multiple roles.'),
('rev_026', 'tt0047396', 'user_018',  8, 'Stewart and Grace Kelly are perfect together. The tension builds masterfully.'),
('rev_027', 'tt0095327', 'user_042',  9, 'Prepare to cry. The most heartbreaking animated film ever made.'),
('rev_028', 'tt0086250', 'user_023',  7, 'Pacino goes full Pacino. An iconic performance in an iconic film.'),
('rev_029', 'tt0209144', 'user_016',  9, 'Watching it backwards has never been so satisfying. Nolan''s indie masterpiece.'),
('rev_030', 'tt0090605', 'user_021',  8, 'Cameron knows how to raise the stakes. The queen reveal still gets me.'),
('rev_031', 'tt0051201', 'user_049',  8, 'A courtroom drama with a twist you won''t see coming. Absolutely brilliant.'),
('rev_048', 'tt1375666', 'user_043',  8, 'The spinning top at the end... I still debate whether he''s dreaming.'),
('rev_049', 'tt0099685', 'user_020',  8, 'Funny, violent, and stylish. Pesci steals every scene he''s in.'),
('rev_050', 'tt0034583', 'user_006',  9, 'Bogart and Bergman have chemistry like no other. A timeless romance wrapped in wartime tension.'),
('rev_051', 'tt0073486', 'user_013', 10, 'Nicholson is electric. A searing look at freedom, conformity, and the cost of defiance.'),
('rev_052', 'tt0095765', 'user_055',  9, 'A love letter to cinema itself. The ending left me speechless for a long time.'),
('rev_053', 'tt8267604', 'user_029', 10, 'Bong Joon-ho masterfully blends genres. A film that gets richer with every rewatch.'),
('rev_054', 'tt0317248', 'user_062',  9, 'Raw and visceral. The handheld camerawork puts you right in the heart of the favela.'),
('rev_055', 'tt0118799', 'user_016', 10, 'Roberto Benigni''s performance is one of the most human things I''ve ever seen on screen.'),
('rev_056', 'tt2582802', 'user_054',  9, 'J.K. Simmons is absolutely terrifying. The final performance sequence is flawless.'),
('rev_057', 'tt0073195', 'user_043',  8, 'Spielberg builds dread like no one else. That first attack scene is still deeply unsettling.'),
('rev_058', 'tt0107290', 'user_030',  9, 'Still holds up thirty years later. The T-rex paddock scene is pure filmmaking magic.'),
('rev_059', 'tt0105236', 'user_058',  8, 'A stripped-back masterpiece. Tarantino proves you don''t need big sets to make a great film.'),
('rev_060', 'tt0407887', 'user_015',  9, 'An all-star cast firing on all cylinders. The ending is one of the most shocking in cinema.'),
('rev_061', 'tt0060196', 'user_063',  9, 'Leone''s direction and Morricone''s score are a perfect marriage. An absolute western legend.'),
('rev_062', 'tt0816692', 'user_046',  8, 'Visually stunning and emotionally ambitious. The docking scene gave me chills.'),
('rev_063', 'tt2380307', 'user_034',  9, 'Pixar at its most soulful. The Remember Me scene is devastating in the best way.'),
('rev_064', 'tt1675434', 'user_067',  9, 'A rare film that made me laugh and cry in equal measure. Omar Sy is magnetic.'),
('rev_065', 'tt0095953', 'user_025',  8, 'Hoffman''s transformation is staggering. Cruise holds his own in a demanding role.'),
('rev_066', 'tt0105695', 'user_023',  8, 'Eastwood directs and stars with quiet authority. A meditation on violence and regret.'),
('rev_067', 'tt0101414', 'user_056',  8, 'The animation was groundbreaking and the music is unforgettable. A Disney high point.'),
('rev_068', 'tt0027977', 'user_016',  9, 'Chaplin''s physical comedy is genius. A surprisingly relevant film about industrialization.'),
('rev_069', 'tt2119532', 'user_043',  8, 'An extraordinary true story told with grit and heart. Garfield is quietly brilliant.'),
('rev_070', 'tt8267676', 'user_067',  1, 'Michael Kovach''s work as Doey was disapointing to say the least.'),
('rev_071', 'tt9046728', 'user_067', 10, 'Colby Jack''s work in this film was unparalleled.'),
('rev_072', 'tt0095067', 'user_067',  9, 'Adam Sandler is my favorite jewish man.');
